query:
SELECT COUNT(*) as total_users FROM users;

SELECT plan, status, COUNT(*) as count, AVG(trialDays) as avg_trial_days
FROM subscriptions
GROUP BY plan, status;

SELECT COUNT(DISTINCT userId) as users_with_fridge FROM fridge_items;

SELECT COUNT(DISTINCT familyProfileId) as family_profiles FROM family_members;

SELECT COUNT(DISTINCT userId) as users_with_menu FROM menu_plans;

SELECT COUNT(*) as total_line_users, 
  SUM(CASE WHEN userId IS NOT NULL THEN 1 ELSE 0 END) as linked_users
FROM line_users;

